      "alternatives_rejected": ["Skip notation testing — would miss a core feature of the component"],
      "reversibility": "easy"
    },
    {
      "id": "d6",
      "decision": "Follow TradingPanel.test.tsx patterns exactly: vi.mock with importActual for session, vi.mock for hooks, vi.mocked() for per-test control, renderWithProviders helper, same fixture structure.",
