      "step": 1,
      "task": "Create test file frontend/src/__tests__/ConditionalEditor.test.tsx with mock setup: vi.mock session context (with importActual), vi.mock hooks (useProbabilityEdit, useMarkets, useMarket all as vi.fn()), import and vi.mocked() all mocked hooks.",
      "depends_on": []
    },
    {
      "step": 2,
      "task": "Define fixtures: mockMarket (same shape as TradingPanel but distinct ids), configuredSession, unconfiguredSession, mockOtherMarkets (2-3 MarketSummary items: one active, one inactive, one matching current market.id to test filtering), mockContextMarketOutcomes (outcomes for a context market returned by useMarket), defaultMutationState helper (reuse pattern from TradingPanel).",
      "depends_on": [1]
    },
    {
      "step": 3,
      "task": "Write beforeEach: vi.clearAllMocks, set default returns for useSession (configured), useProbabilityEdit (idle), useMarkets (returns mockOtherMarkets list), useMarket (returns context market with outcomes).",
      "depends_on": [2]
    },
    {
      "step": 4,
      "task": "Write test: 'shows setup message when session is not configured' — set useSession to unconfigured, verify guard message text, verify no form rendered.",
